  ('pukao-e3452428-moex-00088', 'pukao-e3452428', 'pukao-e3452428-moex-114-d1a761c9', 'sub-pukao-e3452428-03', NULL, 'single_choice', '甲事業於A、B兩縣交界之河床地違法盜採砂石並回填廢棄物，而分別由A、B兩縣主管機關查獲。依行 政程序法規定，下列何者非屬管轄爭議之解決方式？', '["由土石採取法所定之中央主管機關經濟部自為處分", "由土石採取法所定之中央主管機關經濟部指定管轄機關", "由先受理告發案件之A縣主管機關進行處分", "由兩縣政府主管機關協議之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:21+00:00", "source_pdf_sha1": "884c46aa9173", "answer_pdf_sha1": "bd41d588bfdd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "402", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL),
  ('pukao-e3452428-moex-00089', 'pukao-e3452428', 'pukao-e3452428-moex-114-d1a761c9', 'sub-pukao-e3452428-03', NULL, 'single_choice', '關於公務員懲戒權之行使時間，下列敘述何者正確？', '["應受懲戒之行為，自行為終了之日起至案件繫屬懲戒法院之日止已逾10年者，不得予以免除職務之懲戒", "應受懲戒之行為，自行為終了之日起至案件繫屬懲戒法院之日止已逾5年者，不得予以休職之懲戒", "應受懲戒行為終了之日，係指公務員應受懲戒行為所生結果終結之日", "應受懲戒行為係不作為者，係指公務員所屬服務機關或移送機關知悉之日"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:21+00:00", "source_pdf_sha1": "884c46aa9173", "answer_pdf_sha1": "bd41d588bfdd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "402", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL),
